import os
from dataclasses import dataclass, field
from typing import Optional
from langchain_openai import ChatOpenAI, OpenAIEmbeddings
from langchain_community.vectorstores import Chroma
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain_community.document_loaders import DirectoryLoader, PyPDFLoader
from langchain.schema import Document


@dataclass
class RetrievalResult:
    content: str
    source: str
    relevance_score: float
    metadata: dict = field(default_factory=dict)


class RAGAgent:
    """A RAG-powered agent with self-reflective retrieval."""

    def __init__(self, docs_path: str = "./knowledge_base"):
        self.llm = ChatOpenAI(model="gpt-4o", temperature=0)
        self.embeddings = OpenAIEmbeddings()
        self.vectorstore = self._build_vectorstore(docs_path)
        self.retriever = self.vectorstore.as_retriever(
            search_type="similarity_score_threshold",
            search_kwargs={"score_threshold": 0.6, "k": 5}
        )
        self.retrieval_history: list[str] = []

    def _build_vectorstore(self, docs_path: str) -> Chroma:
        """Load documents and build vector store."""
        loader = DirectoryLoader(
            docs_path,
            glob="**/*.pdf",
            loader_cls=PyPDFLoader
        )
        documents = loader.load()

        splitter = RecursiveCharacterTextSplitter(
            chunk_size=1000,
            chunk_overlap=150,
            separators=["\n\n", "\n", ". ", " "]
        )
        chunks = splitter.split_documents(documents)

        return Chroma.from_documents(
            chunks,
            self.embeddings,
            collection_name="agent_knowledge"
        )

    def _should_retrieve(self, query: str) -> bool:
        """Agent decides whether retrieval is necessary."""
        decision_prompt = f"""Analyze this query and decide if external knowledge retrieval is needed.
Query: {query}

Consider:
- Is this a factual question requiring current/specific data?
- Is this about domain-specific knowledge?
- Can this be answered from general knowledge alone?

Respond with ONLY 'RETRIEVE' or 'NO_RETRIEVE'."""

        response = self.llm.invoke(decision_prompt).content.strip()
        return "RETRIEVE" in response.upper()

    def _score_relevance(self, query: str, document: str) -> float:
        """Score how relevant a document is to the query (0-1)."""
        score_prompt = f"""Rate the relevance of this document to the query.
Query: {query}
Document: {document[:500]}

Score from 0.0 (irrelevant) to 1.0 (highly relevant).
Respond with ONLY a number."""

        response = self.llm.invoke(score_prompt).content.strip()
        try:
            return min(max(float(response), 0.0), 1.0)
        except ValueError:
            return 0.0

    def retrieve(self, query: str, min_relevance: float = 0.7) -> list[RetrievalResult]:
        """Retrieve and filter documents based on relevance."""
        docs = self.retriever.invoke(query)
        results = []

        for doc in docs:
            score = self._score_relevance(query, doc.page_content)
            if score >= min_relevance:
                results.append(RetrievalResult(
                    content=doc.page_content,
                    source=doc.metadata.get("source", "unknown"),
                    relevance_score=score,
                    metadata=doc.metadata
                ))

        results.sort(key=lambda x: x.relevance_score, reverse=True)
        self.retrieval_history.append(query)
        return results[:3]

    def answer(self, query: str) -> dict:
        """Main agent loop: decide, retrieve, synthesize."""
        if not self._should_retrieve(query):
            return self._answer_from_memory(query)

        results = self.retrieve(query)

        if not results:
            return {
                "answer": "I could not find relevant information in my knowledge base.",
                "sources": [],
                "retrieval_used": True
            }

        context = "\n\n---\n\n".join(
            f"[Source: {r.source}]\n{r.content}" for r in results
        )

        answer_prompt = f"""Answer the question using ONLY the provided context.
Always cite your sources.

Context:
{context}

Question: {query}

Provide a comprehensive answer with citations."""

        response = self.llm.invoke(answer_prompt).content

        return {
            "answer": response,
            "sources": [{"file": r.source, "score": r.relevance_score} for r in results],
            "retrieval_used": True,
            "num_chunks_retrieved": len(results)
        }

    def _answer_from_memory(self, query: str) -> dict:
        """Answer without retrieval when agent deems it unnecessary."""
        response = self.llm.invoke(query).content
        return {
            "answer": response,
            "sources": [],
            "retrieval_used": False
        }


# Usage Example
if __name__ == "__main__":
    agent = RAGAgent(docs_path="./company_docs")

    # Agent decides retrieval is needed
    result = agent.answer("What is our refund policy for enterprise customers?")
    print(f"Answer: {result['answer']}")
    print(f"Sources: {result['sources']}")

    # Agent decides retrieval is NOT needed
    result = agent.answer("What is 2 + 2?")
    print(f"Answer: {result['answer']}")
    print(f"Retrieval used: {result['retrieval_used']}")
